<script setup>
import { computed, onBeforeUnmount, onMounted, ref, watch } from 'vue'
import api from '@/services/api'
import SoftAurora from './SoftAurora.vue'
import AnimatedList from './AnimatedList.vue'
import ClickSpark from './ClickSpark.vue'
import PillNav from './PillNav.vue'
import Dock from './Dock.vue'

const todos=ref([]),loading=ref(true),saving=ref(false),error=ref(''),view=ref('tasks'),category=ref('all'),status=ref('all')
const form=ref({title:'',category:'work',priority:'medium',due_date:'',amount:''}),showPaymentModal=ref(false)
const categories=[{id:'all',label:'Tümü',icon:'◈'},{id:'work',label:'İş',icon:'▣'},{id:'home',label:'Ev',icon:'⌂'},{id:'school',label:'Okul',icon:'◇'}]
const viewItems=[{id:'tasks',label:'Yapılacaklar',icon:'✓'},{id:'payments',label:'Ödenecekler',icon:'₺'},{id:'habits',label:'Seriler',icon:'◌'},{id:'focus',label:'Odak',icon:'◷'}]
const habits=ref(JSON.parse(localStorage.getItem('odak-habits')||'null')||[{id:'smoke',name:'Sigara',icon:'🚭',since:'2026-07-01',checkins:[]},{id:'alcohol',name:'Alkol',icon:'🍷',since:'2026-07-05',checkins:[]},{id:'sugar',name:'Şeker',icon:'🍬',since:'2026-07-10',checkins:[]}])
const newHabit=ref({name:'',icon:'🌱'}),timerSeconds=ref(25*60),timerRunning=ref(false),studyTotal=ref(Number(localStorage.getItem('study-total')||0));let timerId
const savedTheme=localStorage.getItem('evolve-theme')
const darkMode=ref(savedTheme?savedTheme==='dark':window.matchMedia?.('(prefers-color-scheme: dark)').matches??false)
const currentType=computed(()=>view.value==='tasks'?'task':'payment')
const visible=computed(()=>view.value==='habits'?[]:todos.value.filter(t=>t.type===currentType.value&&(view.value==='payments'||category.value==='all'||t.category===category.value)&&(status.value==='all'||(status.value==='open'?!t.completed:t.completed))))
const openTasks=computed(()=>todos.value.filter(t=>t.type==='task'&&!t.completed).length)
const pendingPayments=computed(()=>todos.value.filter(t=>t.type==='payment'&&!t.completed).reduce((sum,t)=>sum+Number(t.amount||0),0))
const allUpcomingPayments=computed(()=>todos.value.filter(t=>t.type==='payment'&&!t.completed&&t.due_date).sort((a,b)=>a.due_date.localeCompare(b.due_date)))
const upcomingPayments=computed(()=>allUpcomingPayments.value.slice(0,4))
const upcomingTotal=computed(()=>allUpcomingPayments.value.reduce((sum,t)=>sum+Number(t.amount||0),0))
const today=computed(()=>new Intl.DateTimeFormat('tr-TR',{weekday:'long',day:'numeric',month:'long'}).format(new Date()))
const pageMeta=computed(()=>({tasks:['GÖREVLER','Yapılacaklar','İşlerini kategorilere ayır, gününü planla.'],payments:['FİNANS','Ödenecekler','Faturalarını ve yaklaşan ödemelerini takip et.'],habits:['İYİ YAŞAM','Temiz Seriler','Bıraktığın alışkanlıkları gün gün takip et.'],focus:['DERİN ÇALIŞMA','Odak Zamanı','Zamanını ölç, düzenli çalışma ritmi kazan.'],pets:['EVCİL DOSTLAR','Bakım Takibi','Aşı, veteriner ve mama durumunu tek yerde tut.']}[view.value]))
const money=value=>new Intl.NumberFormat('tr-TR',{style:'currency',currency:'TRY'}).format(value||0)
const date=value=>value?new Intl.DateTimeFormat('tr-TR',{day:'numeric',month:'short'}).format(new Date(`${value}T00:00:00`)):'Tarih yok'
function paymentTiming(payment){const due=new Date(`${payment.due_date}T00:00:00`),today=new Date();today.setHours(0,0,0,0);const days=Math.round((due-today)/86400000),label=date(payment.due_date);if(days<0)return `${label} · ${Math.abs(days)} gün gecikti`;if(days===0)return `${label} · bugün`;if(days===1)return `${label} · yarın`;return `${label} · ${days} gün kaldı`}
function notify(message){error.value=message||'İşlem tamamlanamadı.';setTimeout(()=>error.value='',4000)}
async function load(){loading.value=true;try{todos.value=(await api.get('/todos')).data;showPaymentModal.value=allUpcomingPayments.value.length>0}catch{notify('Veriler yüklenemedi. Backend bağlantısını kontrol edin.')}finally{loading.value=false}}
async function add(){const title=form.value.title.trim();if(!title)return;saving.value=true;try{const payload={title,type:currentType.value,category:view.value==='tasks'?form.value.category:null,priority:view.value==='tasks'?form.value.priority:null,due_date:form.value.due_date||null,amount:view.value==='payments'?Number(form.value.amount):null};todos.value.unshift((await api.post('/todos',payload)).data);form.value={title:'',category:form.value.category,priority:'medium',due_date:'',amount:''}}catch(e){notify(e.response?.data?.message)}finally{saving.value=false}}
async function toggle(todo){const old=todo.completed;todo.completed=!old;try{Object.assign(todo,(await api.put(`/todos/${todo.id}`,{completed:todo.completed})).data)}catch{todo.completed=old;notify()}}
async function remove(todo){const i=todos.value.indexOf(todo);todos.value.splice(i,1);try{await api.delete(`/todos/${todo.id}`)}catch{todos.value.splice(i,0,todo);notify()}}
function switchView(id){view.value=id;category.value='all';status.value='all'}
const streak=habit=>Math.max(0,Math.floor((Date.now()-new Date(`${habit.since}T00:00:00`))/86400000)+1)
function markClean(habit){const today=new Date().toISOString().slice(0,10);if(!habit.checkins.includes(today))habit.checkins.push(today);localStorage.setItem('odak-habits',JSON.stringify(habits.value))}
function resetHabit(habit){habit.since=new Date().toISOString().slice(0,10);habit.checkins=[];localStorage.setItem('odak-habits',JSON.stringify(habits.value))}
function addHabit(){if(!newHabit.value.name.trim())return;habits.value.push({id:Date.now(),name:newHabit.value.name.trim(),icon:newHabit.value.icon||'🌱',since:new Date().toISOString().slice(0,10),checkins:[]});newHabit.value={name:'',icon:'🌱'};localStorage.setItem('odak-habits',JSON.stringify(habits.value))}
function removeHabit(habit){habits.value=habits.value.filter(h=>h.id!==habit.id);localStorage.setItem('odak-habits',JSON.stringify(habits.value))}
const timerText=computed(()=>`${String(Math.floor(timerSeconds.value/60)).padStart(2,'0')}:${String(timerSeconds.value%60).padStart(2,'0')}`)
function toggleTimer(){timerRunning.value=!timerRunning.value;if(timerRunning.value){timerId=setInterval(()=>{if(timerSeconds.value>0){timerSeconds.value--;studyTotal.value++;localStorage.setItem('study-total',studyTotal.value)}else{clearInterval(timerId);timerRunning.value=false}},1000)}else clearInterval(timerId)}
function setTimer(minutes){clearInterval(timerId);timerRunning.value=false;timerSeconds.value=minutes*60}
function toggleTheme(){darkMode.value=!darkMode.value}
watch(darkMode,value=>{document.documentElement.dataset.theme=value?'dark':'light';localStorage.setItem('evolve-theme',value?'dark':'light')},{immediate:true})
onMounted(load)
onBeforeUnmount(()=>clearInterval(timerId))
</script>

<template>
<ClickSpark :spark-color="darkMode?'#D9B6E8':'#A88AC4'" :spark-size="11" :spark-radius="20" :spark-count="8" :duration="480">
<div class="shell"><SoftAurora :key="darkMode?'dark':'light'" class="aurora" :speed=".38" :scale="1.7" :brightness="darkMode ? .32 : .32" :color1="darkMode?'#4A365F':'#D4C1E8'" :color2="darkMode?'#5E334D':'#EAC5D4'" :mouse-influence=".1" />
  <nav class="navbar">
    <button class="logo" aria-label="Blossom ana sayfa" @click="switchView('tasks')"><span class="logo-mark" aria-hidden="true"><svg viewBox="0 0 24 24"><ellipse cx="12" cy="6.5" rx="3.1" ry="5"/><ellipse cx="12" cy="6.5" rx="3.1" ry="5" transform="rotate(72 12 12)"/><ellipse cx="12" cy="6.5" rx="3.1" ry="5" transform="rotate(144 12 12)"/><ellipse cx="12" cy="6.5" rx="3.1" ry="5" transform="rotate(216 12 12)"/><ellipse cx="12" cy="6.5" rx="3.1" ry="5" transform="rotate(288 12 12)"/><circle cx="12" cy="12" r="2.6"/></svg></span><strong>BLOSSOM</strong></button>
    <PillNav class="top-pills" :items="viewItems" :model-value="view" @update:model-value="switchView" />
    <div class="date">{{ today }}</div>
    <button class="theme-toggle" :aria-label="darkMode?'Açık moda geç':'Koyu moda geç'" :title="darkMode?'Açık moda geç':'Koyu moda geç'" @click="toggleTheme"><span aria-hidden="true">{{ darkMode?'☀':'☾' }}</span><b>{{ darkMode?'Açık':'Koyu' }}</b></button>
  </nav>

  <main class="layout">
    <aside>
      <p class="side-label">GENEL BAKIŞ</p>
      <button :class="{active:view==='tasks'&&category==='all'}" @click="switchView('tasks')"><span>◈</span> Tüm görevler <b>{{ openTasks }}</b></button>
      <button :class="{active:view==='payments'}" @click="switchView('payments')"><span>₺</span> Ödenecekler</button>
      <template v-if="view==='tasks'"><p class="side-label section">KATEGORİLER</p><PillNav compact :items="categories" :model-value="category" @update:model-value="category=$event" /></template>
      <div class="payment-card"><span>Bekleyen ödemeler</span><strong>{{ money(pendingPayments) }}</strong></div>
    </aside>

    <section class="content">
      <header class="page-head"><div><p>{{ view==='tasks'?(categories.find(c=>c.id===category)?.label||'Tümü'):pageMeta[0] }}</p><h1>{{ pageMeta[1] }}</h1><span>{{ pageMeta[2] }}</span></div><div v-if="view==='tasks'||view==='payments'" class="status"><button :class="{active:status==='all'}" @click="status='all'">Tümü</button><button :class="{active:status==='open'}" @click="status='open'">Bekleyen</button><button :class="{active:status==='done'}" @click="status='done'">Tamamlanan</button></div></header>

      <form v-if="view==='habits'" class="quick-add" @submit.prevent="addHabit"><input v-model="newHabit.icon" class="emoji-input" maxlength="2" aria-label="Simge"><input v-model="newHabit.name" placeholder="Yeni bir alışkanlık ekle…"><button>Ekle</button></form>
      <div v-if="view==='habits'" class="habit-grid"><article v-for="habit in habits" :key="habit.id" class="habit-card"><div class="habit-icon">{{ habit.icon }}</div><p>{{ habit.name }} olmadan</p><strong>{{ streak(habit) }} <small>gün</small></strong><div class="habit-progress"><span :style="{width:`${Math.min(streak(habit)/30*100,100)}%`}"></span></div><em>{{ habit.checkins.includes(new Date().toISOString().slice(0,10))?'Bugün kaydedildi ✓':'Bugün henüz işaretlenmedi' }}</em><button @click="markClean(habit)">Bugün temizim</button><button class="reset" @click="resetHabit(habit)">Seriyi sıfırla</button><button class="habit-delete" @click="removeHabit(habit)">Kaldır</button></article></div>
      <section v-else-if="view==='focus'" class="focus-panel"><div class="timer-ring"><span>ODAK OTURUMU</span><strong>{{ timerText }}</strong><em>{{ timerRunning?'Odaklanıyorsun…':'Başlamaya hazır' }}</em></div><div class="timer-actions"><button @click="setTimer(25)">25 dk</button><button @click="setTimer(45)">45 dk</button><button @click="setTimer(60)">60 dk</button></div><button class="timer-main" @click="toggleTimer">{{ timerRunning?'Duraklat':'Çalışmaya başla' }}</button><div class="study-stat"><span>Toplam çalışma</span><strong>{{ Math.floor(studyTotal/3600) }} sa {{ Math.floor(studyTotal%3600/60) }} dk</strong></div><p class="focus-tip">Telefonunu sessize al, tek bir hedef seç ve süre bitene kadar yalnızca ona odaklan.</p></section>
      <form v-else class="composer" @submit.prevent="add">
        <div class="main-input"><span>＋</span><input v-model="form.title" maxlength="255" :placeholder="view==='tasks'?'Yeni bir görev ekle…':'Ödeme veya fatura adı…'" /></div>
        <div class="form-options">
          <label v-if="view==='tasks'">Kategori<select v-model="form.category"><option value="work">İş</option><option value="home">Ev</option><option value="school">Okul</option></select></label>
          <label v-if="view==='tasks'">Öncelik<select v-model="form.priority"><option value="low">Düşük</option><option value="medium">Orta</option><option value="high">Yüksek</option></select></label>
          <label v-if="view==='payments'">Tutar (₺)<input v-model="form.amount" type="number" min="0" step=".01" placeholder="0,00" /></label>
          <label>{{ view==='tasks'?'Son tarih':'Ödeme tarihi' }}<input v-model="form.due_date" type="date" /></label>
          <button class="add" :disabled="!form.title.trim()||saving">{{ saving?'Ekleniyor…':'Ekle' }}</button>
        </div>
      </form>
      <div v-if="error" class="alert">{{ error }}</div>
      <div v-if="!['tasks','payments'].includes(view)"></div><div v-else-if="loading" class="empty">Yükleniyor…</div>
      <div v-else-if="!visible.length" class="empty"><i>{{ view==='tasks'?'✓':'₺' }}</i><h2>{{ status==='all'?'Burası şimdilik boş':'Bu filtrede kayıt yok' }}</h2><p>Yukarıdaki alandan ilk kaydını ekleyebilirsin.</p></div>
      <AnimatedList v-else :items="visible" item-key="id" :show-gradients="true">
        <template #default="{item}"><article class="todo" :class="{done:item.completed}"><button class="check" @click="toggle(item)">✓</button><div class="todo-copy"><strong>{{ item.title }}</strong><div><span v-if="item.category" class="tag">{{ categories.find(c=>c.id===item.category)?.label }}</span><span v-if="item.priority" :class="['priority',item.priority]">{{ {low:'Düşük',medium:'Orta',high:'Yüksek'}[item.priority] }}</span><span>◷ {{ date(item.due_date) }}</span></div></div><strong v-if="item.type==='payment'" class="amount">{{ money(item.amount) }}</strong><button class="delete" @click="remove(item)">×</button></article></template>
      </AnimatedList>
    </section>
  </main>
  <Dock :items="viewItems" :active="view" @select="switchView" />
  <Transition name="modal"><div v-if="showPaymentModal&&allUpcomingPayments.length" class="modal-backdrop" @click.self="showPaymentModal=false"><section class="payment-modal upcoming-modal" role="dialog" aria-modal="true" aria-labelledby="upcoming-title"><button class="modal-close" aria-label="Kapat" @click="showPaymentModal=false">×</button><div class="modal-icon">{{ allUpcomingPayments.length }}</div><p>YAKLAŞAN ÖDEMELER</p><h2 id="upcoming-title">Ödemelerini gözden geçir</h2><div class="upcoming-list"><article v-for="payment in upcomingPayments" :key="payment.id" class="upcoming-payment"><div><strong>{{ payment.title }}</strong><span>{{ paymentTiming(payment) }}</span></div><strong class="upcoming-amount">{{ money(payment.amount) }}</strong></article></div><div v-if="allUpcomingPayments.length>upcomingPayments.length" class="upcoming-more">+{{ allUpcomingPayments.length-upcomingPayments.length }} ödeme daha</div><div class="upcoming-summary"><span>Toplam bekleyen</span><strong>{{ money(upcomingTotal) }}</strong></div><button class="modal-action" @click="switchView('payments');showPaymentModal=false">Ödemelere git</button></section></div></Transition>
</div></ClickSpark>
</template>

<style>
@import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=Manrope:wght@600;700;800&display=swap');
:root{font-family:'DM Sans',sans-serif;color:#e8f0ef;background:#091011}*{box-sizing:border-box}body{margin:0}button,input,select{font:inherit}.shell{position:relative;isolation:isolate;min-height:100vh;overflow:hidden;background:#091011}.aurora{z-index:-1;pointer-events:none}.navbar{height:74px;display:flex;align-items:center;padding:0 max(24px,calc((100vw - 1180px)/2));border-bottom:1px solid #253234;background:rgba(11,18,20,.78);backdrop-filter:blur(18px)}button{cursor:pointer}.logo{display:flex;align-items:center;gap:10px;border:0;color:#eaf4f2;background:none;font-size:20px}.logo span{display:grid;place-items:center;width:34px;height:34px;border-radius:10px;color:#0c1816;background:#55d6b1}.nav-tabs{display:flex;align-self:stretch;margin-left:70px}.nav-tabs button{position:relative;padding:0 22px;border:0;color:#7d8c8f;background:none;font-weight:600}.nav-tabs button.active{color:#eaf4f2}.nav-tabs button.active:after{content:'';position:absolute;left:22px;right:22px;bottom:-1px;height:2px;background:#55d6b1}.date{margin-left:auto;color:#728184;font-size:13px;text-transform:capitalize}.layout{position:relative;z-index:1;display:grid;grid-template-columns:230px 1fr;gap:50px;width:min(1180px,calc(100% - 48px));margin:0 auto;padding:42px 0}aside{padding-right:26px;border-right:1px solid #222e31}.side-label{margin:0 0 12px;color:#566568;font-size:10px;font-weight:700;letter-spacing:.16em}.side-label.section{margin-top:32px}aside>button{display:flex;align-items:center;gap:11px;width:100%;margin:3px 0;padding:11px;border:0;border-radius:10px;color:#829194;background:transparent;text-align:left}aside>button span{width:20px;color:#6a7a7d;font-size:17px}aside>button b{margin-left:auto;font-size:11px}aside>button:hover,aside>button.active{color:#e7f1ef;background:#1a2729}aside>button.active span{color:#55d6b1}.payment-card{display:flex;flex-direction:column;gap:7px;margin-top:36px;padding:17px;border:1px solid #263538;border-radius:13px;background:rgba(20,31,33,.75)}.payment-card span{color:#718184;font-size:11px}.payment-card strong{color:#70e0bd;font:700 17px 'Manrope'}.content{min-width:0}.page-head{display:flex;align-items:flex-end;justify-content:space-between;margin-bottom:25px}.page-head p{margin:0 0 6px;color:#55d6b1;font-size:10px;font-weight:700;letter-spacing:.17em}.page-head h1{margin:0;font:800 31px 'Manrope';letter-spacing:-.04em}.page-head>div>span{display:block;margin-top:7px;color:#748386;font-size:13px}.status{display:flex;padding:4px;border-radius:10px;background:#10191b}.status button{padding:7px 11px;border:0;border-radius:7px;color:#657477;background:none;font-size:11px}.status button.active{color:#dfe9e7;background:#263336}.composer{padding:9px;border:1px solid #2b3b3e;border-radius:16px;background:rgba(14,23,25,.94)}.main-input{display:flex;align-items:center}.main-input span{padding-left:10px;color:#55d6b1;font-size:21px}.main-input input{width:100%;padding:13px;border:0;outline:0;color:#e8f1ef;background:transparent}.form-options{display:flex;align-items:flex-end;gap:9px;padding-top:9px;border-top:1px solid #223033}.form-options label{display:flex;flex-direction:column;gap:5px;color:#657477;font-size:10px}.form-options input,.form-options select{min-width:120px;padding:8px 10px;border:1px solid #2b3b3e;border-radius:8px;outline:0;color:#bfcac8;background:#121d1f;font-size:11px;color-scheme:dark}.form-options .add{margin-left:auto;padding:9px 20px;border:0;border-radius:9px;color:#091310;background:#55d6b1;font-weight:700}.form-options .add:disabled{opacity:.4}.alert{margin-top:12px;padding:11px;border:1px solid #5e3737;border-radius:10px;color:#ffb6ae;background:#2e1c1d;font-size:12px}.empty{display:grid;place-items:center;min-height:290px;color:#6d7b7e;text-align:center}.empty i{display:grid;place-items:center;width:52px;height:52px;border:1px dashed #3a4b4e;border-radius:15px;color:#55d6b1;font-style:normal;font-size:21px}.empty h2{margin:12px 0 0;color:#b8c5c3;font:700 16px 'Manrope'}.empty p{margin:0;font-size:12px}.todo{display:flex;align-items:center;gap:13px;min-height:67px;padding:12px 14px;border:1px solid #263639;border-radius:13px;background:rgba(19,30,32,.92);transition:.2s}.todo:hover{border-color:#3d5255;transform:translateY(-1px)}.check{display:grid;place-items:center;width:24px;height:24px;flex:0 0 auto;border:1.5px solid #526468;border-radius:8px;color:transparent;background:none}.done .check{border-color:#55d6b1;color:#0a1513;background:#55d6b1}.todo-copy{min-width:0;flex:1}.todo-copy>strong{display:block;margin-bottom:7px;color:#dce7e5;font-size:14px}.done .todo-copy>strong{text-decoration:line-through;color:#647477}.todo-copy>div{display:flex;align-items:center;gap:8px;color:#637275;font-size:10px}.tag,.priority{padding:3px 7px;border-radius:5px;background:#263538}.priority.high{color:#ff9489;background:#382526}.priority.medium{color:#e7bd70;background:#352f24}.priority.low{color:#72c7ad;background:#20332e}.amount{margin-right:8px;color:#7ae1c0;font:700 14px 'Manrope'}.delete{width:29px;height:29px;border:0;border-radius:8px;color:#6f7f82;background:none;font-size:20px}.delete:hover{color:#ff9287;background:#372426}@media(max-width:800px){.navbar{padding:0 18px}.nav-tabs{margin-left:25px}.date{display:none}.layout{display:block;width:min(100% - 28px,680px);padding-top:25px}aside{display:flex;gap:5px;margin-bottom:25px;padding:0 0 16px;overflow:auto;border-right:0;border-bottom:1px solid #243033}aside .side-label,aside .payment-card{display:none}aside>button{flex:0 0 auto;width:auto}.page-head{align-items:flex-start;flex-direction:column;gap:18px}.form-options{flex-wrap:wrap}.form-options .add{min-height:34px}.form-options label{flex:1}.form-options input,.form-options select{width:100%;min-width:110px}}@media(max-width:520px){.logo strong{display:none}.nav-tabs{margin-left:8px}.nav-tabs button{padding:0 10px}.nav-tabs button.active:after{left:10px;right:10px}.page-head h1{font-size:26px}.form-options .add{width:100%;margin:0}.todo-copy>div{flex-wrap:wrap}}
.shell{color:#473f55;background:radial-gradient(circle at 14% 16%,rgba(255,207,228,.96),transparent 34%),radial-gradient(circle at 86% 12%,rgba(190,215,255,.92),transparent 36%),radial-gradient(circle at 52% 88%,rgba(211,194,246,.94),transparent 42%),linear-gradient(135deg,#f9e9f2 0%,#e8efff 48%,#eee5fa 100%)}
.navbar{background:rgba(217,202,233,.86);border-bottom-color:rgba(100,78,125,.14);box-shadow:0 8px 30px rgba(91,72,117,.08)}.logo{color:#44384f}.logo span{color:#fff;background:#9b7bb2}.nav-tabs button{color:#75677f}.nav-tabs button.active{color:#493c55}.nav-tabs button.active:after{background:#a37bb4}.date{color:#796b82}
aside{border-right-color:rgba(93,73,112,.14)}.side-label{color:#887992}aside>button{color:#75677f}aside>button span{color:#9584a0}aside>button:hover,aside>button.active{color:#493e54;background:rgba(205,186,222,.72)}aside>button.active span{color:#956daa}.payment-card{border-color:rgba(112,87,133,.16);background:rgba(220,205,234,.78);box-shadow:0 12px 30px rgba(93,70,114,.08)}.payment-card span{color:#7e7088}.payment-card strong{color:#7b5a91}.page-head p{color:#956daa}.page-head h1{color:#493d54}.page-head>div>span{color:#766b7e}.status{background:rgba(215,199,229,.72)}.status button{color:#82738b}.status button.active{color:#4a3d55;background:#f2eafa;box-shadow:0 3px 12px rgba(100,76,121,.09)}
